#include <stdio.h>
#include <stdlib.h>

int main()
{
    long int a,b,c;
    while(~scanf("%ld",&a))
    {
        if(a>=5)
        {
            b=a/5;
            c=a%5;
            if(c!=0)
            {
                b++;
                printf("%ld\n",b);
            }
            else
                printf("%ld\n",b);
        }
        if(a<5)
        printf("1\n");
    }
    return 0;
}

