use std::io::{BufReader, BufRead};

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let mut distance = BufReader::new(std::io::stdin())
        .lines()
        .map(Result::unwrap)
        .next()
        .unwrap()
        .parse::<usize>()?;

    let mut steps = 0;
    for step in &[5, 4, 3, 2, 1] {
        if distance == 0 { break }
        steps += distance / step;
        distance %= step;
    }

    println!("{}", steps);
    Ok(())
}
